1	const PROCESSING_FEE = 5;
2	
3	interface Item {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	}
9	
10	interface Damage {
11	  itemType: string;
12	  amount: number;
13	}
14	
15	interface Incident {
16	  cause?: string;
17	  damages: Damage[];
18	}
19	
20	interface Step {
21	  op: string;
22	  items?: Item[];
23	  policy?: number;
24	  incident?: Incident;
25	}
26	
27	interface Customer {
28	  yearsWithMHPCO: number;
29	}
30	
31	interface Scenario {
32	  customer: Customer;
33	  steps: Step[];
34	}
35	
36	const BASE_PREMIUMS: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const INSURANCE_VALUES: Record<string, number> = {
46	  sword: 1000,
47	  amulet: 600,
48	  staff: 800,
49	  potion: 400,
50	  rune: 250,
51	  moonstone: 250,
52	};
53	
54	const DEDUCTIBLE = 100;
55	const CAP_MULTIPLIER = 2;
56	
57	const basePremium = (item: Item): number => {
58	  if (!(item.type in BASE_PREMIUMS)) {
59	    throw new Error(`Unknown item type: ${item.type}`);
60	  }
61	  return BASE_PREMIUMS[item.type];
62	};
63	
64	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
65	const BLOCK_SIZE = 3;
66	const BLOCK_PRICE = 60;
67	
68	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
69	
70	const countByType = (items: Item[]): Record<string, number> =>
71	  items.reduce<Record<string, number>>((counts, item) => {
72	    counts[item.type] = (counts[item.type] ?? 0) + 1;
73	    return counts;
74	  }, {});
75	
76	const componentGroupPremium = (type: string, count: number): number =>
77	  count === BLOCK_SIZE ? BLOCK_PRICE : count * basePremium({ type });
78	
79	const componentsPremium = (components: Item[]): number => {
80	  const counts = countByType(components);
81	  return Object.entries(counts).reduce(
82	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
83	    0,
84	  );
85	};
86	
87	const CURSED_SURCHARGE_RATE = 0.5;
88	const HIGH_ENCHANTMENT_THRESHOLD = 5;
89	const HIGH_ENCHANTMENT_RATE = 0.3;
90	const FIRST_INSURANCE_RATE = 0.1;
91	const LOYALTY_YEARS_THRESHOLD = 2;
92	const LOYALTY_DISCOUNT_RATE = 0.2;
93	const FOLLOWUP_DISCOUNT_RATE = 0.15;
94	
95	const itemSurcharges = (item: Item): number => {
96	  const base = basePremium(item);
97	  let extras = 0;
98	  if (item.cursed) extras += base * CURSED_SURCHARGE_RATE;
99	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
100	    extras += base * HIGH_ENCHANTMENT_RATE;
101	  }
102	  return extras;
103	};
104	
105	interface PremiumBreakdown {
106	  withSurcharges: number;
107	  baseOnly: number;
108	}
109	
110	const itemsPremiumBreakdown = (items: Item[]): PremiumBreakdown => {
111	  const mainItems = items.filter((i) => !isComponent(i));
112	  const componentsTotal = componentsPremium(items.filter(isComponent));
113	  const mainBase = mainItems.reduce((sum, item) => sum + basePremium(item), 0);
114	  const mainSurcharges = mainItems.reduce((sum, item) => sum + itemSurcharges(item), 0);
115	  return {
116	    withSurcharges: mainBase + mainSurcharges + componentsTotal,
117	    baseOnly: mainBase + componentsTotal,
118	  };
119	};
120	
121	const policyModifiers = (
122	  customer: Customer,
123	  policyBase: number,
124	  isFollowUp: boolean,
125	): number => {
126	  let modifiers = policyBase * FIRST_INSURANCE_RATE;
127	  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
128	    modifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
129	  }
130	  if (isFollowUp) {
131	    modifiers -= policyBase * FOLLOWUP_DISCOUNT_RATE;
132	  }
133	  return modifiers;
134	};
135	
136	const computeQuotePremium = (
137	  customer: Customer,
138	  items: Item[],
139	  isFollowUp: boolean,
140	): number => {
141	  const { withSurcharges, baseOnly } = itemsPremiumBreakdown(items);
142	  const raw = withSurcharges + policyModifiers(customer, baseOnly, isFollowUp) + PROCESSING_FEE;
143	  return Math.ceil(raw);
144	};
145	
146	interface Policy {
147	  items: Item[];
148	  cap: number;
149	}
150	
151	const policyInsuranceSum = (items: Item[]): number =>
152	  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
153	
154	const computeClaim = (
155	  policy: Policy,
156	  incident: Incident,
157	): { payout: number; remainingCap: number } => {
158	  const totalPayout = incident.damages.reduce(
159	    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
160	    0,
161	  );
162	  return {
163	    payout: Math.floor(totalPayout),
164	    remainingCap: policy.cap - totalPayout,
165	  };
166	};
167	
168	export const runScenario = (scenario: Scenario): unknown => {
169	  let quoteCount = 0;
170	  const policies: Policy[] = [];
171	  const results = scenario.steps.map((step) => {
172	    if (step.op === "claim") {
173	      const policy = policies[step.policy ?? 0];
174	      return computeClaim(policy, step.incident as Incident);
175	    }
176	    const items = step.items ?? [];
177	    const isFollowUp = quoteCount > 0;
178	    quoteCount += 1;
179	    policies.push({ items, cap: policyInsuranceSum(items) * CAP_MULTIPLIER });
180	    return { premium: computeQuotePremium(scenario.customer, items, isFollowUp) };
181	  });
182	  return { results };
183	};
